solution_code:
#include <iostream>

int main() {
    int R, C;
    std::cin >> R >> C;

    int** grid = new int*[R];
    for (int r = 0; r < R; ++r)
        grid[r] = new int[C]{};

    for (int r = 0; r < R; ++r)
        for (int c = 0; c < C; ++c)
            std::cin >> grid[r][c];

    for (int r = 0; r < R; ++r) {
        int sum = 0;
        for (int c = 0; c < C; ++c)
            sum += grid[r][c];
        std::cout << "Row " << r << ": " << sum << "\n";
    }

    for (int r = 0; r < R; ++r)
        delete[] grid[r];
    delete[] grid;
    return 0;
}

