solution_code:
#include <iostream>

void addToAll(int** pp, int delta) {
    **pp += delta;
}

int main() {
    int val, delta;
    std::cin >> val >> delta;

    int* p = new int{val};
    addToAll(&p, delta);
    std::cout << "Result: " << *p << "\n";
    delete p;
    return 0;
}
